SELECT c.id_cliente, s.marca, s.modelo, CONVERT(VARCHAR(100),s.anio), s.placa
FROM #SimClientes s
JOIN dbo.clientes c ON c.identificacion=s.cedula
WHERE NOT EXISTS (SELECT 1 FROM dbo.autos a WHERE a.placa=s.placa);
GO
CREATE TABLE #SimAutosExtra (cedula NVARCHAR(20), marca NVARCHAR(100), modelo NVARCHAR(100), anio INT, placa NVARCHAR(100));
GO
CREATE TABLE #SimCitas (codigo NVARCHAR(20), cedula NVARCHAR(20), servicio NVARCHAR(150), marca NVARCHAR(100), modelo NVARCHAR(100), anio INT, fecha DATE, hora TIME, estado NVARCHAR(20), monto_base DECIMAL(10,2));
SELECT c.id_cliente, sv.id_servicio, sc.marca, sc.modelo, sc.anio, sc.fecha, sc.hora, CONCAT(sc.codigo, ' - ', sc.servicio, ' para ', sc.marca, ' ', sc.modelo), sc.estado, DATEADD(DAY,-30,CAST(sc.fecha AS DATETIME))
FROM #SimCitas sc JOIN dbo.clientes c ON c.identificacion=sc.cedula JOIN dbo.servicios sv ON sv.nombre=sc.servicio
WHERE NOT EXISTS (SELECT 1 FROM dbo.citas x WHERE x.descripcion LIKE sc.codigo + '%');
GO
CREATE TABLE #SimPagos (codigo NVARCHAR(20), factura NVARCHAR(20), metodo NVARCHAR(50), monto DECIMAL(10,2), recibido DECIMAL(10,2), referencia NVARCHAR(100), banco NVARCHAR(100));
SELECT p.factura, ci.id_cita, u.id_usuario, mp.id_metodo, p.monto, p.recibido, p.recibido-p.monto, NULLIF(p.referencia,N''), NULLIF(p.banco,N''), N'Pago simulado registrado correctamente', N'COMPLETADO', DATEADD(DAY,1,CAST(ci.fecha AS DATETIME))
FROM #SimPagos p JOIN dbo.citas ci ON ci.descripcion LIKE p.codigo + '%' JOIN dbo.metodos_pago mp ON mp.nombre=p.metodo CROSS APPLY (SELECT TOP 1 id_usuario FROM dbo.usuarios WHERE correo LIKE N'%simcr@retrogarage.co.cr' AND activo=1 ORDER BY id_usuario) u
WHERE NOT EXISTS (SELECT 1 FROM dbo.pagos x WHERE x.numero_factura=p.factura);
GO
CREATE TABLE #SimMovs (codigo_item NVARCHAR(50), codigo_cita NVARCHAR(20), usuario_correo NVARCHAR(100), tipo NVARCHAR(20), cantidad INT, stock_anterior INT, stock_resultante INT, motivo NVARCHAR(300), dias_atras INT);
SELECT pr.id_producto, ci.id_cita, u.id_usuario, m.tipo, m.cantidad, m.stock_anterior, m.stock_resultante, m.motivo, DATEADD(DAY,-m.dias_atras,GETDATE())
FROM #SimMovs m JOIN dbo.productos pr ON pr.codigo_item=m.codigo_item JOIN dbo.usuarios u ON u.correo=m.usuario_correo LEFT JOIN dbo.citas ci ON m.codigo_cita<>N'' AND ci.descripcion LIKE m.codigo_cita + '%';
GO
SELECT id_usuario, CONCAT(N'tok_simcr_', id_usuario, N'_', FORMAT(GETDATE(),'yyyyMMddHHmmss')), N'190.10.25.11', DATEADD(HOUR,-2,GETDATE()), DATEADD(HOUR,6,GETDATE()), 1 FROM dbo.usuarios WHERE correo LIKE N'%simcr@retrogarage.co.cr';
GO
SELECT 'Carga masiva adicional finalizada' AS resultado,
(SELECT COUNT(*) FROM dbo.clientes) AS total_clientes,
(SELECT COUNT(*) FROM dbo.autos) AS total_autos,
(SELECT COUNT(*) FROM dbo.citas) AS total_citas,
(SELECT COUNT(*) FROM dbo.pagos) AS total_pagos,
(SELECT COUNT(*) FROM dbo.movimientos_inventario) AS total_movimientos;
GO